import{_ as n,o as s,c as e,ak as l}from"./chunks/framework.DwHlt8HN.js";const b=JSON.parse('{"title":"微服务架构设计","description":"","frontmatter":{},"headers":[],"relativePath":"distributed/theory/microservices.md","filePath":"distributed/theory/microservices.md","lastUpdated":1774318215000}'),r={name:"distributed/theory/microservices.md"};function i(p,a,t,o,h,d){return s(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="微服务架构设计" tabindex="-1">微服务架构设计 <a class="header-anchor" href="#微服务架构设计" aria-label="Permalink to “微服务架构设计”">​</a></h1><p>你有没有这种感觉：写代码一年，突然发现整个系统像一个巨大的意大利面条——这里改一行，那里就崩了；没人完全理解整个系统是怎么工作的；每次上线都像拆炸弹。</p><p>恭喜你，你可能正在经历「单体地狱」。</p><p>微服务架构，就是来解决这个问题的。</p><hr><h2 id="微服务的定义" tabindex="-1">微服务的定义 <a class="header-anchor" href="#微服务的定义" aria-label="Permalink to “微服务的定义”">​</a></h2><p>微服务没有官方定义，但社区公认的核心特征是：</p><blockquote><p><strong>每个服务围绕业务能力构建，可独立部署、独立扩展。</strong></p></blockquote><p>翻译成人话：一个微服务只做一件事，而且这件事可以独立上线，不需要等其他团队。</p><p>比如：</p><ul><li>用户服务：只管用户注册、登录、资料</li><li>订单服务：只管订单创建、支付、取消</li><li>库存服务：只管库存查询、扣减、返还</li></ul><p>每个服务有自己的数据库，服务之间通过 API 通信。</p><hr><h2 id="微服务-vs-单体-不是「非此即彼」" tabindex="-1">微服务 vs 单体：不是「非此即彼」 <a class="header-anchor" href="#微服务-vs-单体-不是「非此即彼」" aria-label="Permalink to “微服务 vs 单体：不是「非此即彼」”">​</a></h2><p>很多人误解微服务，觉得它是银弹，恨不得第一天就把系统拆成 100 个微服务。</p><p><strong>这是一个危险的想法。</strong></p><p>微服务解决的是「大型团队的协作问题」，不是「代码组织问题」。</p><table tabindex="0"><thead><tr><th>场景</th><th>推荐架构</th></tr></thead><tbody><tr><td>小团队（&lt; 10 人）、业务简单</td><td>单体起步</td></tr><tr><td>中型团队（10-50 人）、业务复杂</td><td>渐进式拆分</td></tr><tr><td>大型团队（&gt; 50 人）、高并发</td><td>微服务 + 容器化</td></tr></tbody></table><p><strong>单体不是原罪。</strong> Twitter、Netflix 早期都是单体，只是后来团队太大了，单体成了瓶颈，才拆的。</p><hr><h2 id="微服务拆分维度" tabindex="-1">微服务拆分维度 <a class="header-anchor" href="#微服务拆分维度" aria-label="Permalink to “微服务拆分维度”">​</a></h2><p>拆分的核心原则是<strong>业务边界</strong>（Bounded Context），这是 Eric Evans 在《领域驱动设计》里提出的概念。</p><h3 id="按业务边界拆分" tabindex="-1">按业务边界拆分 <a class="header-anchor" href="#按业务边界拆分" aria-label="Permalink to “按业务边界拆分”">​</a></h3><p>强相关、同步调用的功能，拆到同一个服务。</p><p>比如「下单」这个功能，涉及到：</p><ul><li>用户验证（用户服务）</li><li>库存扣减（库存服务）</li><li>支付扣款（支付服务）</li><li>订单创建（订单服务）</li></ul><p>这些应该拆成 4 个服务吗？不一定。</p><p>如果「下单」是一个高频操作，需要强一致性，可能把「下单」做成一个服务，内部调用用户、库存、支付的 API 更合理。</p><h3 id="按团队所有权拆分" tabindex="-1">按团队所有权拆分 <a class="header-anchor" href="#按团队所有权拆分" aria-label="Permalink to “按团队所有权拆分”">​</a></h3><p>一个服务应该由一个团队完全负责，从开发到部署到运维。</p><p>如果一个服务需要两个团队同时修改，那就是拆分失败的信号。</p><hr><h2 id="微服务的四大黄金原则" tabindex="-1">微服务的四大黄金原则 <a class="header-anchor" href="#微服务的四大黄金原则" aria-label="Permalink to “微服务的四大黄金原则”">​</a></h2><h3 id="原则一-独立部署" tabindex="-1">原则一：独立部署 <a class="header-anchor" href="#原则一-独立部署" aria-label="Permalink to “原则一：独立部署”">​</a></h3><p>每个服务可以独立部署，不需要协调其他团队。</p><p>如果你的「微服务」每次上线还需要通知其他 5 个团队，那它不是微服务，是「分布式巨石」。</p><h3 id="原则二-无共享数据" tabindex="-1">原则二：无共享数据 <a class="header-anchor" href="#原则二-无共享数据" aria-label="Permalink to “原则二：无共享数据”">​</a></h3><p>每个服务有自己的数据库，表不共享。</p><p>如果服务 A 直接读写服务 B 的数据库表，恭喜你，你把网络调用变成了 SQL 调用，问题更多。</p><h3 id="原则三-异构技术" tabindex="-1">原则三：异构技术 <a class="header-anchor" href="#原则三-异构技术" aria-label="Permalink to “原则三：异构技术”">​</a></h3><p>每个服务可以用不同的技术栈。</p><p>Python 团队做机器学习服务，Java 团队做交易系统，Go 团队做高并发网关——这是微服务的优势。</p><p>但前提是：<strong>技术选型要服务于业务，而不是为了炫技。</strong></p><h3 id="原则四-故障隔离" tabindex="-1">原则四：故障隔离 <a class="header-anchor" href="#原则四-故障隔离" aria-label="Permalink to “原则四：故障隔离”">​</a></h3><p>一个服务挂了，不能导致整个系统崩溃。</p><p>常见的故障隔离手段：</p><ul><li><strong>舱壁模式</strong>：不同服务用不同的连接池</li><li><strong>熔断器</strong>：服务不可用时快速失败，不无限重试</li><li><strong>限流</strong>：保护服务不被突发流量冲垮</li></ul><hr><h2 id="微服务的技术栈全景图" tabindex="-1">微服务的技术栈全景图 <a class="header-anchor" href="#微服务的技术栈全景图" aria-label="Permalink to “微服务的技术栈全景图”">​</a></h2><p>构建微服务需要很多组件：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                      微服务架构                          │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  服务框架：Spring Cloud / Dubbo / gRPC                   │</span></span>
<span class="line"><span>│  通信协议：HTTP REST / gRPC / Dubbo RPC                 │</span></span>
<span class="line"><span>│  服务注册：Nacos / Eureka / Consul                      │</span></span>
<span class="line"><span>│  配置中心：Apollo / Nacos Config / Spring Config        │</span></span>
<span class="line"><span>│  网关层：Spring Cloud Gateway / Kong / Zuul             │</span></span>
<span class="line"><span>│  认证鉴权：JWT / OAuth2 / Spring Security              │</span></span>
<span class="line"><span>│  分布式事务：Seata / TX-LCN / Saga                      │</span></span>
<span class="line"><span>│  链路追踪：SkyWalking / Zipkin / Jaeger                 │</span></span>
<span class="line"><span>│  日志聚合：ELK / Loki / EFK                            │</span></span>
<span class="line"><span>│  容器化：Docker + Kubernetes                            │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p>每个组件都有其适用场景，后面会专门讲。</p><hr><h2 id="微服务陷阱" tabindex="-1">微服务陷阱 <a class="header-anchor" href="#微服务陷阱" aria-label="Permalink to “微服务陷阱”">​</a></h2><p>微服务不是银弹，它带来了新的问题：</p><h3 id="陷阱一-过度拆分" tabindex="-1">陷阱一：过度拆分 <a class="header-anchor" href="#陷阱一-过度拆分" aria-label="Permalink to “陷阱一：过度拆分”">​</a></h3><p>把一个简单的 CRUD 应用拆成 20 个微服务，每个服务就 3 张表、5 个接口。</p><p>结果：20 个服务 = 20 个数据库 = 20 套配置 = 20 套监控 = 20 倍的运维复杂度。</p><p><strong>建议</strong>：当一个服务的代码量超过 10 万行，或者团队超过 5 个人专门维护时，再考虑拆分。</p><h3 id="陷阱二-分布式复杂性爆炸" tabindex="-1">陷阱二：分布式复杂性爆炸 <a class="header-anchor" href="#陷阱二-分布式复杂性爆炸" aria-label="Permalink to “陷阱二：分布式复杂性爆炸”">​</a></h3><p>单体里一个函数调用解决的问题，微服务里可能涉及：</p><ul><li>网络调用</li><li>序列化/反序列化</li><li>服务发现</li><li>负载均衡</li><li>熔断降级</li><li>分布式事务</li></ul><p>这不是换一套框架能解决的，是架构层面的复杂度转移。</p><h3 id="陷阱三-数据一致性" tabindex="-1">陷阱三：数据一致性 <a class="header-anchor" href="#陷阱三-数据一致性" aria-label="Permalink to “陷阱三：数据一致性”">​</a></h3><p>单体里一个数据库事务解决的问题，微服务里需要分布式事务或最终一致性。</p><p>这是一道鸿沟，没有完美的解决方案，只有业务层面的 trade-off。</p><hr><h2 id="什么时候不该用微服务" tabindex="-1">什么时候不该用微服务 <a class="header-anchor" href="#什么时候不该用微服务" aria-label="Permalink to “什么时候不该用微服务”">​</a></h2><p>微服务是有成本的，以下场景建议先不要用：</p><ol><li><strong>小团队</strong>：运维成本可能超过收益</li><li><strong>业务简单</strong>：不需要高扩展、高可用</li><li><strong>创业初期</strong>：快速验证业务比架构重要</li><li><strong>强一致性场景</strong>：微服务天然是最终一致，强一致需要额外的工程成本</li></ol><hr><h2 id="面试追问方向" tabindex="-1">面试追问方向 <a class="header-anchor" href="#面试追问方向" aria-label="Permalink to “面试追问方向”">​</a></h2><p><strong>微服务和 SOA 有什么区别？</strong></p><p>SOA 有 ESB 总线，所有服务通过 ESB 通信；微服务去中心化，服务之间直接通信。SOA 是粗粒度，微服务是细粒度。</p><p><strong>微服务如何保证数据一致性？</strong></p><p>这是一个开放性问题，没有标准答案：</p><ul><li>强一致：分布式事务（2PC/TCC/Saga）</li><li>最终一致：消息队列 + 补偿机制</li><li>业务层处理：乐观锁 + 重试 + 对账</li></ul><p><strong>服务拆分后，接口版本怎么管理？</strong></p><ul><li>URL 路径：<code>/api/v1/users</code></li><li>Header：<code>API-Version: 1.0</code></li><li>蓝绿部署：新旧版本并行，流量切换</li></ul><hr><h2 id="留给你的问题" tabindex="-1">留给你的问题 <a class="header-anchor" href="#留给你的问题" aria-label="Permalink to “留给你的问题”">​</a></h2><p>微服务解决了「大型团队的协作问题」，但引入了「分布式系统的复杂度问题」。</p><p>你有没有遇到过这种情况：一个功能，单体里 1 小时搞定，微服务里需要 1 周（分布式事务 + 服务间联调 + 链路追踪 + ...）？</p><p>如果是你，会怎么权衡？</p>`,84)])])}const g=n(r,[["render",i]]);export{b as __pageData,g as default};
